   291|export async function updateRequestStatus(
   292|  requestId: string,
   293|  status: EquipmentRequest['status'],
   294|  currentUid: string
   295|): Promise<void> {
   296|  const db = getFirebaseDb();
   297|  console.log('[Firestore] Updating request status:', requestId, '->', status);
   298|
   299|  const snap = await getDoc(doc(db, 'equipmentRequests', requestId));
   300|  if (!snap.exists()) throw new Error('Request not found');
   301|
   302|  const request = snap.data();
   303|  const isProvider = request.providerUid === currentUid;
   304|  const isCustomer = request.customerUid === currentUid;
   305|
   306|  const validTransitions: Record<string, { allowed: string[]; who: 'provider' | 'customer' | 'both' }> = {
   307|    pending: { allowed: ['accepted', 'rejected', 'cancelled'], who: 'both' },
   308|    accepted: { allowed: ['in_progress', 'cancelled'], who: 'both' },
   309|    in_progress: { allowed: ['completed'], who: 'provider' },
   310|  };
   311|
   312|  const current = request.status as string;
   313|  const rule = validTransitions[current];
   314|
   315|  if (!rule || !rule.allowed.includes(status)) {
   316|    throw new Error(`Invalid status transition: ${current} -> ${status}`);
   317|  }
   318|
   319|  if (rule.who === 'provider' && !isProvider) {
   320|    throw new Error('Only the provider can perform this action');
   321|  }
   322|
   323|  if (status === 'cancelled' && !isCustomer && !isProvider) {
   324|    throw new Error('Only participants can cancel');
