    20|export function getRemovedImages(
    21|  oldImages: EquipmentImage[],
    22|  newImages: EquipmentImage[]
    23|): string[] {
    24|  const newUrls = new Set(
    25|    newImages.map(img => (typeof img === 'string' ? img : img.url))
